-- DDL: Source Tables

CREATE TABLE src_products (brand_id INT PRIMARY KEY, description VARCHAR(255), size VARCHAR(50), category VARCHAR(100), volume VARCHAR(50), current_unit_price DECIMAL(10,2), current_unit_cost DECIMAL(10,2));
CREATE TABLE src_vendors (vendor_id INT PRIMARY KEY, vendor_name VARCHAR(255), contact_name VARCHAR(255), address TEXT);
CREATE TABLE src_stores (store_id INT PRIMARY KEY, city VARCHAR(100), state VARCHAR(100), zip_code VARCHAR(20));
CREATE TABLE src_purchases (po_number VARCHAR(50), order_date DATE, vendor_id INT, store_id INT, brand_id INT, quantity INT, unit_cost DECIMAL(10,2));
CREATE TABLE src_receiving (receiving_id SERIAL PRIMARY KEY, received_date DATE, po_number VARCHAR(50), brand_id INT, qty_received INT, qty_damaged INT);
CREATE TABLE src_sales (receipt_id VARCHAR(50), sale_date DATE, store_id INT, brand_id INT, qty_sold INT, unit_price DECIMAL(10,2), promo_flag INT);

